onClick:
{{
  (() => {
    // 1. Sinaliza atividade para o sistema de segurança
    JSutils.resetInactivityTimer();	
		// 2. Montagem dos dados com proteção contra nulos (|| "")
    const formData = {
      prop001_id:          InputID.text,
      prop001_nome:        (InputNome.text || "").trim().toUpperCase(),
      prop001_endereco:    (InputEndereco.text || "").trim().toUpperCase(),
      prop001_bairro:      (InputBairro.text || "").trim().toUpperCase(),
      prop001_numero:      (InputNumero.text || "").trim().toUpperCase(),
      prop001_complemento: (InputComplemento.text || "").trim().toUpperCase(),
      prop001_cidade:      (InputCidade.text || "").trim().toUpperCase(),
      prop001_email:       (InputEmail.text || "").trim().toLowerCase(),
      // Removido toString() desnecessário, o || "" já garante que é string
      prop001_telefone:    (PhoneInput1Telefone.text || "").trim().replace(/\D/g, ""),
      prop001_celular:     (PhoneInput1Celular.text || "").trim().replace(/\D/g, ""),
      prop001_uf:          (SelectUF.selectedOptionValue || "").trim().toUpperCase(),
      prop001_comissao:    "0",
      prop001_observacao:     (InputObservacao.text || "").trim().toUpperCase(),
      prop001_cep:         (InputCep.text || "").trim().replace(/\D/g, ""),
      prop001_rg:         (InputRG.text || "").trim(),
      prop001_cpf:         (InputCPF.text || "").trim().replace(/\D/g, "")			
    };

    const contexto = appsmith.store.modalContexto?.acaoTipo;

    if (contexto === "ADICIONAR") {
      return JSconfirmation.showModal({
        action: "Insert",
        message: "Deseja salvar este novo registro?",
        icon: "plus",
        color: "green",
        row: formData
      });
    } else {
      return JSconfirmation.showModal({
        action: "Update",
        message: "Deseja salvar as alterações deste registro?",
        icon: "edit",
        color: "orange",
        row: formData
      });
    }
  })()
}}
